// web/lib/mock/sse.ts
import type { SSEEvent } from "../api/types";

type SSEListener = (event: SSEEvent) => void;

let counter = 0;
function uid(): string {
  return `sse-${Date.now()}-${++counter}`;
}

class MockSSE {
  private listeners: SSEListener[] = [];
  private interval: ReturnType<typeof setInterval> | null = null;

  subscribe(listener: SSEListener) {
    this.listeners.push(listener);
    if (!this.interval) this.startEmitting();
    return () => {
      this.listeners = this.listeners.filter((l) => l !== listener);
      if (this.listeners.length === 0 && this.interval) {
        clearInterval(this.interval);
        this.interval = null;
      }
    };
  }

  private startEmitting() {
    const factories: Array<() => SSEEvent> = [
      () => ({
        id: uid(),
        type: "release.created",
        data: {
          id: `r-live-${Date.now()}`,
          source: "dockerhub",
          repository: "library/golang",
          raw_version: `1.23.${Math.floor(Math.random() * 10)}`,
          created_at: new Date().toISOString(),
        },
        timestamp: new Date().toISOString(),
      }),
      () => ({
        id: uid(),
        type: "pipeline.node_completed",
        data: {
          release_id: "r-004",
          node: ["regex_normalizer", "changelog_summarizer", "urgency_scorer"][Math.floor(Math.random() * 3)],
          result: { status: "ok" },
        },
        timestamp: new Date().toISOString(),
      }),
      () => ({
        id: uid(),
        type: "pipeline.completed",
        data: {
          release_id: "r-004",
          state: "completed",
