 2→import type { SSEEvent } from "../api/types";
 3→
 4→type SSEListener = (event: SSEEvent) => void;
 5→
 6→let counter = 0;
 7→function uid(): string {
 8→  return `sse-${Date.now()}-${++counter}`;
 9→}
10→
11→class MockSSE {
12→  private listeners: SSEListener[] = [];
13→  private interval: ReturnType<typeof setInterval> | null = null;
14→
15→  subscribe(listener: SSEListener) {
16→    this.listeners.push(listener);
17→    if (!this.interval) this.startEmitting();
18→    return () => {
19→      this.listeners = this.listeners.filter((l) => l !== listener);
20→      if (this.listeners.length === 0 && this.interval) {
21→        clearInterval(this.interval);
22→        this.interval = null;
23→      }
24→    };
25→  }
26→
27→  private startEmitting() {
28→    const factories: Array<() => SSEEvent> = [
29→      () => ({
30→        id: uid(),
31→        type: "release.created",
32→        data: {
33→          id: `r-live-${Date.now()}`,
34→          source: "dockerhub",
35→          repository: "library/golang",
36→          raw_version: `1.23.${Math.floor(Math.random() * 10)}`,
37→          created_at: new Date().toISOString(),
