39→        timestamp: new Date().toISOString(),
40→      }),
41→      () => ({
42→        id: uid(),
43→        type: "pipeline.node_completed",
44→        data: {
45→          release_id: "r-004",
46→          node: ["regex_normalizer", "changelog_summarizer", "urgency_scorer"][Math.floor(Math.random() * 3)],
47→          result: { status: "ok" },
48→        },
49→        timestamp: new Date().toISOString(),
50→      }),
51→      () => ({
52→        id: uid(),
53→        type: "pipeline.completed",
54→        data: {
55→          release_id: "r-004",
56→          state: "completed",
57→        },
58→        timestamp: new Date().toISOString(),
59→      }),
60→      () => ({
61→        id: uid(),
62→        type: "source.polled",
63→        data: {
64→          source_id: Math.floor(Math.random() * 6) + 1,
65→          repository: ["library/golang", "ethereum/client-go", "library/postgres"][Math.floor(Math.random() * 3)],
66→          new_releases: Math.floor(Math.random() * 2),
67→        },
68→        timestamp: new Date().toISOString(),
69→      }),
70→    ];
71→
72→    this.interval = setInterval(() => {
73→      const factory = factories[Math.floor(Math.random() * factories.length)];
74→      const event = factory();
75→      this.listeners.forEach((l) => l(event));
76→    }, 5000); // Emit every 5 seconds
77→  }
