 4→import { useEffect, useState, type ReactNode } from "react";
 5→
 6→export function MSWProvider({ children }: { children: ReactNode }) {
 7→  const [ready, setReady] = useState(false);
 8→
 9→  useEffect(() => {
10→    if (process.env.NODE_ENV !== "development") {
11→      setReady(true);
12→      return;
13→    }
14→
15→    import("./mock/browser").then(({ worker }) => {
16→      worker.start({ onUnhandledRequest: "bypass" }).then(() => setReady(true));
17→    });
18→  }, []);
19→
20→  if (!ready) return null;
21→  return <>{children}</>;
22→}
